const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

let lastFrameTime = performance.now();
let player = { x: 50, y: 50, speed: 100 }; // speed in pixels per second
let keys = {};

window.addEventListener('keydown', (e) => keys[e.key] = true);
window.addEventListener('keyup', (e) => keys[e.key] = false);

function update(deltaTime) {
  let distance = player.speed * deltaTime;
  if (keys['ArrowUp']) player.y -= distance;
  if (keys['ArrowDown']) player.y += distance;
  if (keys['ArrowLeft']) player.x -= distance;
  if (keys['ArrowRight']) player.x += distance;
}

function render() {
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.fillStyle = 'blue';
  ctx.fillRect(player.x, player.y, 20, 20);
}

function gameLoop() {
  let currentFrameTime = performance.now();
  let deltaTime = (currentFrameTime - lastFrameTime) / 1000;
  lastFrameTime = currentFrameTime;

  update(deltaTime);
  render();

  requestAnimationFrame(gameLoop);
}

function secureGameLoop() {
  setInterval(() => {
    let currentFrameTime = performance.now();
    let deltaTime = (currentFrameTime - lastFrameTime) / 1000;
    lastFrameTime = currentFrameTime;

    update(deltaTime);
    render();
  }, 1000 / 60);
}

secureGameLoop();